 border-radius: 5px;
 padding: 30px 15px 0px;
 }
 .raya-many-pdf-static .mt60{margin-top:60px}
 .raya-many-pdf-static .h50{height:50px;}
 .raya-many-pdf-static-slider .swiper-slide {
 width: 172px;
 opacity: 0;
 }
 .raya-many-pdf-static-slider .layout-ratio {
 padding-bottom: 175%;
 }
 .raya-many-pdf-static-slider .swiper-slide-prev, .raya-many-pdf-static-slider .swiper-slide-next {
 filter: blur(3px);
 opacity: 1;
 }
 .raya-many-pdf-static-slider .swiper-slide-active {
 opacity: 1;
 }
 .raya-many-pdf-static-slider .swiper-horizontal>.swiper-pagination-bullets, .raya-many-pdf-static-slider .swiper-pagination-bullets.swiper-pagination-horizontal, .raya-many-pdf-static-slider .swiper-pagination-custom, .swiper-pagination-fraction{
 bottom: -40px;
 }
 .raya-many-pdf-static-slider .swiper-button-prev, .raya-many-pdf-static-slider .swiper-button-next {
 bottom: -40px !important;
 }
 setTimeout(function() {
 new Swiper('.swiper-many-pdf', {
 loop: true,
 pagination: {
 el: '.swiper-pagination',
 },
 navigation: {
 nextEl: '.swiper-button-next',
 prevEl: '.swiper-button-prev',
 },
 effect: "coverflow",
 grabCursor: true,
 centeredSlides: true,
 slidesPerView: "auto",
 coverflowEffect: {
 rotate: 0,
 stretch: 0,
 depth: 1200,
 modifier: 1,
 slideShadows: true,
 },
 });
 }, 1000);

